// 获取 binary 数据（兼容 n8n 各种 binary mode）
const item = $input.first();
let buffer;

try {
    // 推荐方式：使用 n8n helper（支持 filesystem 和 base64 模式）
    buffer = await this.helpers.getBinaryDataBuffer(0, 'data');  // 'data' 是 binary property name
} catch (e) {
    // 兼容旧版或直接 base64 的 fallback
    const binaryData = item.binary?.data;
    if (binaryData && typeof binaryData === 'string') {
        buffer = Buffer.from(binaryData, 'base64');
    } else if (Buffer.isBuffer(binaryData)) {
        buffer = binaryData;
    } else {
        return [{ json: { error: '无法获取 binary 数据，请检查上游节点 binary property name 是否为 "data"' } }];
    }
}

// FLAC duration 解析函数
function getFlacDurationFromBinary(buffer) {
    try {
        if (buffer.length < 4 || buffer.toString('utf8', 0, 4) !== 'fLaC') {
            return { error: '不是有效的 FLAC 文件（缺少 fLaC 头）' };
        }

        let offset = 4;  // 跳过 fLaC 标记

        while (offset < buffer.length) {
            // 读取 4 字节 metadata block header (Big Endian)
            const blockHeader = buffer.readUInt32BE(offset);
            offset += 4;

            const isLast = (blockHeader & 0x80000000) !== 0;
            const blockType = (blockHeader >> 24) & 0x7F;  // 类型
            const blockSize = blockHeader & 0x00FFFFFF;    // 大小

            // STREAMINFO block (type 0) 必须是第一个，通常紧跟 fLaC
            if (blockType === 0) {
                // STREAMINFO 数据从这里开始（34 字节固定结构）
                const streamInfoOffset = offset;

                // Sample rate: 20 bits，从 STREAMINFO 第 10 字节开始
                // 字节 10-11 (high 16 bits) + 字节12 高4位
                const sampleRate = ((buffer.readUInt16BE(streamInfoOffset + 10) << 4) |
                                   (buffer.readUInt8(streamInfoOffset + 12) >> 4)) & 0xFFFFF;

                // Total samples: 36 bits，从 STREAMINFO 第 13 字节开始 (Big-endian)
                // 使用 readBigUInt64BE 简化 + 掩码取低36位
                const totalSamplesHigh = buffer.readUInt8(streamInfoOffset + 13) & 0x0F; // 只取低4位
                const totalSamples = (BigInt(totalSamplesHigh) << 32n) |
                                     BigInt(buffer.readUInt32BE(streamInfoOffset + 14));

                if (sampleRate > 0 && totalSamples > 0n) {
                    const durationSeconds = Number(totalSamples) / sampleRate;
                    const minutes = Math.floor(durationSeconds / 60);
                    const seconds = Math.floor(durationSeconds % 60);

                    return {
                        duration_seconds: durationSeconds,
                        duration_formatted: `${minutes}:${seconds.toString().padStart(2, '0')}`,
                        sample_rate: sampleRate,
                        total_samples: Number(totalSamples)
                    };
                } else {
                    return { error: 'STREAMINFO 中 total_samples 或 sample_rate 为 0（未知时长）' };
                }
            }

            offset += blockSize;
            if (isLast) break;
        }

        return { error: '未找到 STREAMINFO metadata block' };
    } catch (error) {
        return { error: `解析错误: ${error.message}` };
    }
}

const result = getFlacDurationFromBinary(buffer);

if (result.error) {
    return [{ json: { error: result.error } }];
}

// 返回 duration_ms
return [{
    json: {
        duration_ms: Math.floor(result.duration_seconds * 1000),
        duration_seconds: result.duration_seconds,
        duration_formatted: result.duration_formatted,
        sample_rate: result.sample_rate,
        total_samples: result.total_samples
    }
}];
